concept.syntax:
// String: heap-allocated — move on assignment
let s1 = String::from("hello");
let s2 = s1;          // s1 is moved into s2
// s1 is now invalid — use s2

// i32: Copy — duplicated on assignment
let n1 = 5;
let n2 = n1;          // n1 is still valid

// Passing to a function also moves ownership
fn take(s: String) { }  // s dropped here
take(s2);              // s2 moved into take()
// s2 no longer valid

demo.code:
fn main() {
    let s1 = String::from("hello");
    let s2 = s1;  // move
    println!("{}", s2);

    let n1 = 5;
    let n2 = n1;  // copy
    println!("{} {}", n1, n2);
}

